diff --git a/src/SecureAPIManager.Codeunit.al b/src/SecureAPIManager.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/SecureAPIManager.Codeunit.al
@@ -0,0 +1,46 @@
+codeunit 50100 "Secure API Manager"
+{
+    Access = Internal;
+
+    var
+        KeyNotConfiguredErr: Label 'API key is not configured for %1.', Comment = '%1 = configuration code';
+        RequestFailedErr: Label 'The API request failed. Check the configuration.', Comment = 'Shown when an outbound API call fails.';
+        EndpointTok: Label 'https://api.businesscentral.dynamics.com/v2.0/data', Locked = true;
+        BearerTok: Label 'Bearer %1', Locked = true;
+        StorageKeyTok: Label 'ApiKey_%1', Locked = true;
+
+    [NonDebuggable]
+    procedure StoreKey(ConfigCode: Code[20]; KeyValue: SecretText)
+    begin
+        IsolatedStorage.SetEncrypted(GetStorageKey(ConfigCode), KeyValue, DataScope::Module);
+    end;
+
+    [NonDebuggable]
+    procedure GetKey(ConfigCode: Code[20]) Result: SecretText
+    begin
+        if not IsolatedStorage.Contains(GetStorageKey(ConfigCode), DataScope::Module) then
+            Error(KeyNotConfiguredErr, ConfigCode);
+        IsolatedStorage.Get(GetStorageKey(ConfigCode), DataScope::Module, Result);
+    end;
+
+    procedure CallEndpoint(ConfigCode: Code[20])
+    var
+        Client: HttpClient;
+        Headers: HttpHeaders;
+        Response: HttpResponseMessage;
+        AuthHeader: SecretText;
+    begin
+        AuthHeader := SecretStrSubstNo(BearerTok, GetKey(ConfigCode));
+        Headers := Client.DefaultRequestHeaders();
+        Headers.Add('Authorization', AuthHeader);
+        if not Client.Get(EndpointTok, Response) then
+            Error(RequestFailedErr);
+        if not Response.IsSuccessStatusCode() then
+            Error(RequestFailedErr);
+    end;
+
+    local procedure GetStorageKey(ConfigCode: Code[20]): Text[50]
+    begin
+        exit(CopyStr(StrSubstNo(StorageKeyTok, ConfigCode), 1, 50));
+    end;
+}
