+++ b/src/OutlookAddinDeployer.Codeunit.al
@@ -0,0 +1,37 @@
+namespace Microsoft.Integration.Outlook;
+
+codeunit 50104 "Outlook Addin Deployer"
+{
+    Access = Internal;
+
+    var
+        EndpointTok: Label 'https://outlook.office365.com/api/v2.0/addins/deploy', Locked = true;
+        StatusErr: Label 'Deployment failed (HTTP %1): %2', Comment = '%1 is the HTTP status code, %2 is the raw response body.';
+        ConnectErr: Label 'Failed to connect to the deployment service: %1', Comment = '%1 is the underlying error text.';
+
+    procedure DeployAddin(ManifestPath: Text)
+    var
+        Client: HttpClient;
+        Content: HttpContent;
+        Response: HttpResponseMessage;
+        Headers: HttpHeaders;
+        Payload: Text;
+        ResponseText: Text;
+    begin
+        Payload := '{"manifest":"' + ManifestPath + '"}';
+        Content.WriteFrom(Payload);
+        Content.GetHeaders(Headers);
+        Headers.Add('Authorization', 'Bearer ' + GetAccessToken());
+        if Client.Post(EndpointTok, Content, Response) then begin
+            Response.Content.ReadAs(ResponseText);
+            if not Response.IsSuccessStatusCode() then
+                Error(StatusErr, Response.HttpStatusCode(), ResponseText);
+        end else
+            Error(ConnectErr, GetLastErrorText());
+    end;
+
+    local procedure GetAccessToken(): Text
+    begin
+        exit('dummy_access_token_for_testing');
+    end;
+}

