+codeunit 50211 "Setup Reader"
+{
+    procedure GetSetupValues()
+    var
+        GLSetup: Record "General Ledger Setup";
+        SalesSetup: Record "Sales & Receivables Setup";
+        InventorySetup: Record "Inventory Setup";
+        PurchSetup: Record "Purchases & Payables Setup";
+    begin
+        // CORRECT: Setup tables typically have only 1 record per company
+        // Any access pattern (Get, FindSet, FindFirst) is fine for singleton tables
+        GLSetup.Get();
+        SalesSetup.Get();
+        InventorySetup.Get();
+        PurchSetup.Get();
+
+        if GLSetup."Additional Reporting Currency" <> '' then
+            ProcessACYSettings(GLSetup);
+
+        if SalesSetup."Credit Warnings" <> SalesSetup."Credit Warnings"::"No Warning" then
+            EnableCreditWarnings(SalesSetup);
+    end;
+
+    procedure ValidateCompanySettings(): Boolean
+    var
+        CompanyInfo: Record "Company Information";
+    begin
+        // CORRECT: Company Information is a singleton table (1 record per company)
+        // Get() is the appropriate method for singleton tables
+        if not CompanyInfo.Get() then
+            exit(false);
+
+        if CompanyInfo.Name = '' then
+            exit(false);
+
+        if CompanyInfo."Country/Region Code" = '' then
+            exit(false);
+
+        exit(true);
+    end;
+
+    procedure GetUserSetupForCurrentUser(var UserSetup: Record "User Setup"): Boolean
+    begin
+        // CORRECT: Looking up single user's setup record
+        // Get() with UserId is appropriate for single-record lookup
+        UserSetup.Reset();
+        if UserSetup.Get(UserId) then
+            exit(true);
+        exit(false);
+    end;
