+        // Enable credit warning processing
+        Message(CreditWarningsEnabledMsg);
+    end;
+}
diff --git a/src/TempBufferProcessor.Codeunit.al b/src/TempBufferProcessor.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/TempBufferProcessor.Codeunit.al
@@ -0,0 +1,61 @@
+codeunit 50210 "Temp Buffer Processor"
+{
+    procedure ProcessBufferEntries(var TempBuffer: Record "Integer" temporary)
+    var
+        ProcessedCount: Integer;
+        TotalAmount: Decimal;
+        ProcessedEntriesMsg: Label 'Processed %1 entries with total %2', Comment = '%1 = number of entries, %2 = total amount';
+    begin
+        // CORRECT: TempBuffer is temporary — all operations are in-memory, no SQL queries
+        // Any access pattern (FindSet, Get, loops) on temp tables is performant
+        ProcessedCount := 0;
+        TotalAmount := 0;
+
+        if TempBuffer.FindSet() then
+            repeat
+                // This might look suspicious, but it's CORRECT because:
+                // 1. TempBuffer is temporary (in-memory)
+                // 2. No database round trips are happening
+                // 3. All data is already loaded in memory
+                TotalAmount += TempBuffer.Number;
+                ProcessedCount += 1;
+
+                // Even modifying temp records in a loop is fine
+                TempBuffer.Number := TempBuffer.Number * 2;
+                TempBuffer.Modify();
+
+            until TempBuffer.Next() = 0;
+
+        Message(ProcessedEntriesMsg, ProcessedCount, TotalAmount);
+    end;
+
+    procedure BuildTempData(var TempBuffer: Record "Integer" temporary)
+    var
+        i: Integer;
+    begin
+        // CORRECT: Building temp data - all operations are in-memory
+        TempBuffer.Reset();
+        TempBuffer.DeleteAll();
+
+        for i := 1 to 100 do begin
+            TempBuffer.Init();
+            TempBuffer.Number := Random(1000);
+            TempBuffer.Insert();
+        end;
+    end;
+
+    procedure FindMaxValue(var TempBuffer: Record "Integer" temporary): Integer
+    var
+        MaxValue: Integer;
+    begin
+        // CORRECT: Finding max in temp table - no performance concern
+        MaxValue := 0;
+        if TempBuffer.FindSet() then
+            repeat
+                if TempBuffer.Number > MaxValue then
+                    MaxValue := TempBuffer.Number;
+            until TempBuffer.Next() = 0;
+
+        exit(MaxValue);
+    end;
+}
