+++ b/src/GenericFieldCopier.Codeunit.al
@@ -0,0 +1,34 @@
+codeunit 50250 "Generic Field Copier"
+{
+    procedure CopyFieldsByRef(SourceRecRef: RecordRef; var DestRecRef: RecordRef)
+    var
+        SourceFldRef: FieldRef;
+        DestFldRef: FieldRef;
+        i: Integer;
+    begin
+        for i := 1 to SourceRecRef.FieldCount() do begin
+            SourceFldRef := SourceRecRef.FieldIndex(i);
+            if SourceFldRef.Class = FieldClass::Normal then
+                if DestRecRef.FieldExist(SourceFldRef.Number) then begin
+                    DestFldRef := DestRecRef.Field(SourceFldRef.Number);
+                    if DestFldRef.Type = SourceFldRef.Type then
+                        DestFldRef.Value := SourceFldRef.Value;
+                end;
+        end;
+    end;
+
+    procedure CountCopyableFields(SourceRecRef: RecordRef; DestRecRef: RecordRef): Integer
+    var
+        SourceFldRef: FieldRef;
+        i: Integer;
+        CopyableCount: Integer;
+    begin
+        for i := 1 to SourceRecRef.FieldCount() do begin
+            SourceFldRef := SourceRecRef.FieldIndex(i);
+            if SourceFldRef.Class = FieldClass::Normal then
+                if DestRecRef.FieldExist(SourceFldRef.Number) then
+                    CopyableCount += 1;
+        end;
+        exit(CopyableCount);
+    end;
+}
