diff --git a/src/CopyLocationHandler.Codeunit.al b/src/CopyLocationHandler.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/CopyLocationHandler.Codeunit.al
@@ -0,0 +1,68 @@
+codeunit 50261 "Copy Location Handler FP"
+{
+    procedure CopyLocation(SourceCode: Code[10]; TargetCode: Code[10])
+    var
+        SourceLocation: Record Location;
+        TargetLocation: Record Location;
+    begin
+        // CORRECT: SetLoadFields before Get — only loads the fields we actually copy
+        SourceLocation.SetLoadFields(Name, Address, "Address 2", City, "Post Code", "Country/Region Code", "Phone No.", Contact);
+        if not SourceLocation.Get(SourceCode) then
+            exit;
+
+        TargetLocation.Init();
+        TargetLocation.Code := TargetCode;
+        TargetLocation.Name := SourceLocation.Name;
+        TargetLocation.Address := SourceLocation.Address;
+        TargetLocation."Address 2" := SourceLocation."Address 2";
+        TargetLocation.City := SourceLocation.City;
+        TargetLocation."Post Code" := SourceLocation."Post Code";
+        TargetLocation."Country/Region Code" := SourceLocation."Country/Region Code";
+        TargetLocation."Phone No." := SourceLocation."Phone No.";
+        TargetLocation.Contact := SourceLocation.Contact;
+        TargetLocation.Insert(true);
+    end;
+
+    procedure CopyCustomer(SourceNo: Code[20]; TargetNo: Code[20])
+    var
+        SourceCustomer: Record Customer;
+        TargetCustomer: Record Customer;
+    begin
+        // CORRECT: SetLoadFields on Customer (800k rows, 100+ fields) — only loads needed subset
+        SourceCustomer.SetLoadFields(Name, "Name 2", Address, "Address 2", City, "Post Code",
+            "Country/Region Code", "Phone No.", "Customer Posting Group",
+            "Gen. Bus. Posting Group", "Payment Terms Code", "Payment Method Code");
+        if not SourceCustomer.Get(SourceNo) then
+            exit;
+
+        TargetCustomer.Init();
+        TargetCustomer."No." := TargetNo;
+        TargetCustomer.Name := SourceCustomer.Name;
+        TargetCustomer."Name 2" := SourceCustomer."Name 2";
+        TargetCustomer.Address := SourceCustomer.Address;
+        TargetCustomer."Address 2" := SourceCustomer."Address 2";
+        TargetCustomer.City := SourceCustomer.City;
+        TargetCustomer."Post Code" := SourceCustomer."Post Code";
+        TargetCustomer."Country/Region Code" := SourceCustomer."Country/Region Code";
+        TargetCustomer."Phone No." := SourceCustomer."Phone No.";
+        TargetCustomer."Customer Posting Group" := SourceCustomer."Customer Posting Group";
+        TargetCustomer."Gen. Bus. Posting Group" := SourceCustomer."Gen. Bus. Posting Group";
+        TargetCustomer."Payment Terms Code" := SourceCustomer."Payment Terms Code";
+        TargetCustomer."Payment Method Code" := SourceCustomer."Payment Method Code";
+        TargetCustomer.Insert(true);
+    end;
+
+    procedure BackupLocationData(LocationCode: Code[10]): Text
+    var
+        Location: Record Location;
+    begin
+        // CORRECT: SetLoadFields — only 5 of ~40 fields needed for backup
+        Location.SetLoadFields(Name, Address, City, "Country/Region Code");
+        if not Location.Get(LocationCode) then
+            exit('');
+
+        exit(StrSubstNo('%1|%2|%3|%4|%5',
+            Location.Code, Location.Name, Location.Address,
+            Location.City, Location."Country/Region Code"));
+    end;
+}
diff --git a/src/SetupValidator.Codeunit.al b/src/SetupValidator.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/SetupValidator.Codeunit.al
@@ -0,0 +1,102 @@
+codeunit 50260 "Setup Validator FP"
+{
+    procedure ValidateSetup()
+    var
+        FASetup: Record "FA Setup";
+        GLSetup: Record "General Ledger Setup";
+        SalesSetup: Record "Sales & Receivables Setup";
+        PurchSetup: Record "Purchases & Payables Setup";
+        InventorySetup: Record "Inventory Setup";
+    begin
+        // CORRECT: Setup tables are singletons (1 record per company)
+        // Get() on singleton tables is always appropriate and fast
+
+        FASetup.Get();
+        FASetup.TestField("Default Depr. Book");
+
+        GLSetup.Get();
+        GLSetup.TestField("LCY Code");
+        GLSetup.TestField("Posting Allowed From");
+        GLSetup.TestField("Posting Allowed To");
+
+        SalesSetup.Get();
+        SalesSetup.TestField("Customer Nos.");
+
+        PurchSetup.Get();
+        PurchSetup.TestField("Vendor Nos.");
+
+        InventorySetup.Get();
+        InventorySetup.TestField("Item Nos.");
+
+        // Validate cross-setup consistency
+        ValidateCurrencyConsistency(GLSetup, SalesSetup);
+    end;
+
+    procedure GetLocationName(LocationCode: Code[10]): Text
+    var
+        Location: Record Location;
+    begin
+        // CORRECT: SetLoadFields + Get is the Microsoft-recommended pattern
+        // This loads only the required fields, making it more efficient than full Get
+        Location.SetLoadFields(Name);
+        if Location.Get(LocationCode) then
+            exit(Location.Name);
+        exit('');
+    end;
+
+    procedure GetCustomerInfo(CustomerNo: Code[20]; var Name: Text; var CreditLimit: Decimal)
+    var
+        Customer: Record Customer;
+    begin
+        // CORRECT: SetLoadFields pattern for loading specific fields only
+        Customer.SetLoadFields(Name, "Credit Limit (LCY)");
+        if Customer.Get(CustomerNo) then begin
+            Name := Customer.Name;
+            CreditLimit := Customer."Credit Limit (LCY)";
+        end else begin
+            Name := '';
+            CreditLimit := 0;
+        end;
+    end;
+
+    procedure GetVendorPaymentTerms(VendorNo: Code[20]): Code[10]
+    var
+        Vendor: Record Vendor;
+    begin
+        // CORRECT: Loading only the specific field needed
+        Vendor.SetLoadFields("Payment Terms Code");
+        if Vendor.Get(VendorNo) then
+            exit(Vendor."Payment Terms Code");
+        exit('');
+    end;
+
+    local procedure ValidateCurrencyConsistency(GLSetup: Record "General Ledger Setup"; SalesSetup: Record "Sales & Receivables Setup")
+    var
+        Currency: Record Currency;
+    begin
+        // CORRECT: Single Get() call for validation
+        if GLSetup."Additional Reporting Currency" <> '' then begin
+            Currency.Get(GLSetup."Additional Reporting Currency");
+            Currency.TestField("Amount Rounding Precision");
+        end;
+    end;
+
+    procedure ValidateNumberSeries()
+    var
+        SalesSetup: Record "Sales & Receivables Setup";
+        NoSeries: Record "No. Series";
+    begin
+        // CORRECT: Setup validation with related record checks
+        SalesSetup.Get();
+
+        if SalesSetup."Customer Nos." <> '' then begin
+            NoSeries.Get(SalesSetup."Customer Nos.");
+            NoSeries.TestField("Default Nos.", true);
+        end;
+
+        if SalesSetup."Invoice Nos." <> '' then begin
+            NoSeries.Get(SalesSetup."Invoice Nos.");
+            NoSeries.TestField("Default Nos.", true);
+        end;
+    end;
+}
