+table 50130 "EA Agent Status"
+{
+    Caption = 'Agent Run Status';
+    DataClassification = SystemMetadata;
+
+    fields
+    {
+        field(1; "Primary Key"; Code[10])
+        {
+            Caption = 'Primary Key';
+        }
+        field(2; "Last Run"; DateTime)
