+codeunit 50131 "Vend. Entry Edit Handler"
+{
+    Access = Internal;
+
+    procedure UpdateRelatedAdvanceLetterEntries(EntryNo: Integer; Level: Integer)
+    var
+        VendLedgerEntry: Record "Vendor Ledger Entry";
+        RelatedEntry: Record "Vendor Ledger Entry";
+        MaxRecursionLevel: Integer;
+    begin
+        MaxRecursionLevel := 50;
+        if Level > MaxRecursionLevel then
+            Error(MaxRecursionErr, EntryNo);
+
+        VendLedgerEntry.SetLoadFields("Letter No.", "Letter Line No.", "Advance Letter Template Code", "Document No.", "Vendor No.");
+        VendLedgerEntry.ReadIsolation(IsolationLevel::UpdLock);
+        if not VendLedgerEntry.Get(EntryNo) then
+            exit;
+
+        VendLedgerEntry."Letter No." := '';
+        VendLedgerEntry."Letter Line No." := 0;
+        VendLedgerEntry."Advance Letter Template Code" := '';
+        VendLedgerEntry.Modify();
+
+        RelatedEntry.SetLoadFields("Entry No.");
+        RelatedEntry.SetRange("Closed by Entry No.", EntryNo);
+        RelatedEntry.SetRange(Open, false);
+
+        if RelatedEntry.FindSet() then
+            repeat
+                UpdateRelatedAdvanceLetterEntries(RelatedEntry."Entry No.", Level + 1);
+            until RelatedEntry.Next() = 0;
+    end;
+
+    var
+        MaxRecursionErr: Label 'Maximum recursion level exceeded for entry %1', Comment = '%1 = entry number';
