+        }
+        field(3; "Posting Date"; Date)
+        {
+            Caption = 'Posting Date';
+        }
+        field(4; "Entry Type"; Option)
+        {
+            Caption = 'Entry Type';
+            OptionMembers = Purchase,Sale,"Positive Adjmt.","Negative Adjmt.",Transfer,Consumption,Output,"Assembly Consumption","Assembly Output";
+            OptionCaption = 'Purchase,Sale,Positive Adjmt.,Negative Adjmt.,Transfer,Consumption,Output,Assembly Consumption,Assembly Output';
+        }
+        field(5; "Source No."; Code[20])
+        {
+            Caption = 'Source No.';
+        }
+        field(6; "Document No."; Code[20])
+        {
+            Caption = 'Document No.';
+        }
+        field(7; "Location Code"; Code[10])
+        {
+            Caption = 'Location Code';
+            TableRelation = Location;
+        }
+        field(8; "Variant Code"; Code[10])
+        {
+            Caption = 'Variant Code';
+            TableRelation = "Item Variant".Code where("Item No." = field("Item No."));
+        }
+        field(9; Description; Text[100])
+        {
+            Caption = 'Description';
+        }
+        field(10; "Unit of Measure Code"; Code[10])
+        {
+            Caption = 'Unit of Measure Code';
+            TableRelation = "Unit of Measure";
+        }
+        field(11; Quantity; Decimal)
+        {
+            Caption = 'Quantity';
+            DecimalPlaces = 0 : 5;
+        }
+        field(12; "Remaining Quantity"; Decimal)
+        {
+            Caption = 'Remaining Quantity';
+            DecimalPlaces = 0 : 5;
+        }
+        field(13; "Invoiced Quantity"; Decimal)
+        {
+            Caption = 'Invoiced Quantity';
+            DecimalPlaces = 0 : 5;
+        }
+        field(14; Open; Boolean)
+        {
+            Caption = 'Open';
+        }
+        field(15; Positive; Boolean)
+        {
+            Caption = 'Positive';
+        }
+        field(20; "APAC Region Code"; Code[10])
+        {
+            Caption = 'APAC Region Code';
+        }
+        field(21; "APAC Country Code"; Code[10])
+        {
+            Caption = 'APAC Country Code';
+        }
+    }
+
+    keys
+    {
+        key(PK; "Entry No.") { Clustered = true; }
+        key(Key2; "Item No.", "Posting Date") { }
+        key(Key3; "Item No.", Open, "Variant Code", "Unit of Measure Code", "Location Code", "Posting Date") { }
+        key(Key4; "Source No.", "Item No.", "Variant Code", "Posting Date") { }
+        key(Key5; "Item No.", "Entry Type", "Variant Code", "Drop Shipment", "Location Code", "Posting Date") { }
+        key(Key6; "Item No.", Open, "Variant Code", Positive, "Location Code", "Posting Date") { }
+        key(Key7; "Location Code", "Item No.", "Variant Code", Open, Positive)
+        {
+            IncludedFields = Quantity, "Remaining Quantity";
+        }
+        key(Key8; "Country/Region Code", "Entry Type", "Posting Date") { }
+        key(Key9; "Document No.", "Document Type", "Location Code") { }
+        key(Key10; "Item No.", "APAC Region Code", "Posting Date") { }
+    }
+
+    trigger OnInsert()
+    begin
+        if "Posting Date" = 0D then
+            "Posting Date" := Today();
+
+        if "APAC Country Code" = '' then
+            "APAC Country Code" := GetCountryFromLocation("Location Code");
+
+        if "APAC Region Code" = '' then
+            "APAC Region Code" := GetRegionFromCountry("APAC Country Code");
+    end;
+
+    local procedure GetCountryFromLocation(LocationCode: Code[10]): Code[10]
+    var
+        Location: Record Location;
+    begin
+        if Location.Get(LocationCode) then
+            exit(Location."Country/Region Code");
+        exit('');
+    end;
+
+    local procedure GetRegionFromCountry(CountryCode: Code[10]): Code[10]
+    begin
+        // Map country to APAC region
+        case CountryCode of
+            'AU':
+                exit('OCEANIA');
+            'JP', 'KR':
+                exit('NORTHEAST');
+            'CN', 'HK', 'TW':
+                exit('CHINA');
+            'TH', 'SG', 'MY':
+                exit('SOUTHEAST');
+            'IN':
+                exit('SOUTH');
+            else
+                exit('OTHER');
+        end;
+    end;
+}

diff --git a/src/ConfigurationHelper.Codeunit.al b/src/ConfigurationHelper.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/ConfigurationHelper.Codeunit.al
@@ -0,0 +1,77 @@
+codeunit 50400 "Configuration Helper"
+{
+    Access = Internal;
+
+    procedure GetOrCreateSetup(): Record "General Ledger Setup"
+    var
+        GLSetup: Record "General Ledger Setup";
+    begin
+        GLSetup.LockTable();
+        if not GLSetup.Get() then begin
+            GLSetup.Init();
+            GLSetup."Allow Posting From" := CalcDate('<-CM>', WorkDate());
+            GLSetup."Allow Posting To" := CalcDate('<CM>', WorkDate());
+            GLSetup.Insert(true);
+        end;
+        exit(GLSetup);
+    end;
+
+    procedure GetCustomerDisplayName(CustomerNo: Code[20]): Text[100]
+    var
+        Customer: Record Customer;
+    begin
+        Customer.LockTable();
+        Customer.SetLoadFields(Name);
+        Customer.SetRange("No.", CustomerNo);
+        Customer.SetRange(Blocked, Customer.Blocked::" ");
+        if Customer.FindFirst() then
+            exit(Customer.Name);
+        exit('');
+    end;
+
+    procedure GetItemDescription(ItemNo: Code[20]): Text[100]
+    var
+        Item: Record Item;
+    begin
+        Item.ReadIsolation := IsolationLevel::ReadCommitted;
+        Item.SetLoadFields(Description);
+        if Item.Get(ItemNo) then
+            exit(Item.Description);
+        exit('');
+    end;
+
+    procedure GetCurrencyExchangeRate(CurrencyCode: Code[10]; PostingDate: Date): Decimal
+    var
+        CurrencyExchangeRate: Record "Currency Exchange Rate";
+    begin
+        CurrencyExchangeRate.SetRange("Currency Code", CurrencyCode);
+        CurrencyExchangeRate.SetRange("Starting Date", 0D, PostingDate);
+        if CurrencyExchangeRate.FindLast() then
+            exit(CurrencyExchangeRate."Exchange Rate Amount");
+        exit(1);
+    end;
+
+    procedure GetDefaultDimension(TableID: Integer; No: Code[20]): Code[20]
+    var
+        DefaultDimension: Record "Default Dimension";
+    begin
+        DefaultDimension.SetRange("Table ID", TableID);
+        DefaultDimension.SetRange("No.", No);
+        DefaultDimension.SetRange("Dimension Code", 'DEPARTMENT');
+        if DefaultDimension.FindFirst() then
+            exit(DefaultDimension."Dimension Value Code");
+        exit('');
+    end;
+
+    procedure IsFeatureEnabled(FeatureKey: Text[50]): Boolean
+    var
+        FeatureDataUpdateStatus: Record "Feature Data Update Status";
+    begin
+        FeatureDataUpdateStatus.ReadIsolation := IsolationLevel::ReadCommitted;
+        FeatureDataUpdateStatus.SetRange("Feature Key", FeatureKey);
+        if FeatureDataUpdateStatus.FindFirst() then
+            exit(FeatureDataUpdateStatus."Feature Status" = FeatureDataUpdateStatus."Feature Status"::Enabled);
+        exit(false);
+    end;
+}
