diff --git a/src/PostalCodeLookupService.Codeunit.al b/src/PostalCodeLookupService.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/PostalCodeLookupService.Codeunit.al
@@ -0,0 +1,50 @@
+codeunit 50113 "Postal Code Lookup Service"
+{
+    Access = Internal;
+
+    var
+        TypeHelper: Codeunit "Type Helper";
+
+    procedure LookupPostalAddress(PostalCode: Code[20]; City: Text[50]): Text[250]
+    var
+        HttpClient: HttpClient;
+        HttpResponse: HttpResponseMessage;
+        RequestUri: Text;
+        ResponseText: Text;
+    begin
+        HttpClient.Timeout := 10000;
+        RequestUri := StrSubstNo('https://postal-api.service.com/lookup?postal=%1&city=%2',
+            TypeHelper.UrlEncode(PostalCode), TypeHelper.UrlEncode(City));
+
+        if not HttpClient.Get(RequestUri, HttpResponse) then
+            exit('');
+        if not HttpResponse.IsSuccessStatusCode() then
+            exit('');
+
+        HttpResponse.Content.ReadAs(ResponseText);
+        exit(ParseAddressResponse(ResponseText));
+    end;
+
+    local procedure ParseAddressResponse(JsonResponse: Text): Text[250]
+    var
+        JsonObject: JsonObject;
+        AddressToken: JsonToken;
+    begin
+        if JsonObject.ReadFrom(JsonResponse) then
+            if JsonObject.Get('standardized_address', AddressToken) then
+                exit(CopyStr(AddressToken.AsValue().AsText(), 1, 250));
+        exit('');
+    end;
+
+    procedure ValidateBusinessAddress(var BusinessAddress: Record "Business Address")
+    var
+        StandardizedAddress: Text[250];
+    begin
+        StandardizedAddress := LookupPostalAddress(BusinessAddress."Postal Code", BusinessAddress.City);
+        if StandardizedAddress <> '' then begin
+            BusinessAddress."Validated Address" := StandardizedAddress;
+            BusinessAddress."Validation Status" := BusinessAddress."Validation Status"::Validated;
+            BusinessAddress.Modify(true);
+        end;
+    end;
+}
