@@ -0,0 +1,43 @@
+codeunit 50115 SystemErrorHandler
+{
+  var
+    ErrorLoggedMsg: Label 'Error logged with reference: %1', Comment = '%1 = System ID';
+    ValidationFailedMsg: Label 'Validation failed for record %1 in field %2', Comment = '%1 = Record ID, %2 = Field name';
+
+  procedure HandleSystemError(ErrorContext: Text[100]; SystemId: Guid; ErrorDetails: Text[500])
+  var
+    ErrorLogEntry: Record "Error Log Entry";
+  begin
+
+    ErrorLogEntry.Init();
+    ErrorLogEntry."Entry No." := GetNextEntryNo();
+    ErrorLogEntry."Error Context" := ErrorContext;
+    ErrorLogEntry."System Reference" := SystemId;
+    ErrorLogEntry."Error Message" := ErrorDetails;
+    ErrorLogEntry."Date Time" := CurrentDateTime;
+    ErrorLogEntry.Insert();
+
+    Message(ErrorLoggedMsg, SystemId);
+  end;
+
+  procedure ProcessSystemValidationError(RecordId: RecordId; ValidationField: Text[50])
+  var
+    ErrorMessage: Text[500];
+  begin
+
+    ErrorMessage := StrSubstNo(ValidationFailedMsg, Format(RecordId), ValidationField);
+
+    HandleSystemError('VALIDATION', RecordId.SystemId, ErrorMessage);
+
+  end;
+
+  local procedure GetNextEntryNo(): Integer
+  var
+    ErrorLogEntry: Record "Error Log Entry";
+  begin
+    ErrorLogEntry.LockTable();
+    if ErrorLogEntry.FindLast() then
+      exit(ErrorLogEntry."Entry No." + 1);
+    exit(1);
+  end;
+}
