diff --git a/src/BusinessIntegrationEvents.Codeunit.al b/src/BusinessIntegrationEvents.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/BusinessIntegrationEvents.Codeunit.al
@@ -0,0 +1,38 @@
+codeunit 50117 "Business Integration Events"
+{
+    Access = Internal;
+
+    [IntegrationEvent(true, false)]
+    local procedure OnBeforeProcessBusinessEntity(var BusinessEntity: Record "Business Entity"; var IsHandled: Boolean)
+    begin
+    end;
+
+    procedure ProcessBusinessEntityBatch(var TempBusinessEntity: Record "Business Entity" temporary)
+    var
+        IsHandled: Boolean;
+        ProcessedCount: Integer;
+    begin
+        if TempBusinessEntity.FindSet() then
+            repeat
+                IsHandled := false;
+                OnBeforeProcessBusinessEntity(TempBusinessEntity, IsHandled);
+                if not IsHandled then begin
+                    ProcessSingleBusinessEntity(TempBusinessEntity);
+                    ProcessedCount += 1;
+                end;
+                OnAfterBusinessEntityProcessed(TempBusinessEntity."Entity No.", ProcessedCount);
+            until TempBusinessEntity.Next() = 0;
+    end;
+
+    [IntegrationEvent(true, false)]
+    local procedure OnAfterBusinessEntityProcessed(EntityNo: Code[20]; ProcessedCount: Integer)
+    begin
+    end;
+
+    local procedure ProcessSingleBusinessEntity(var BusinessEntity: Record "Business Entity")
+    begin
+        BusinessEntity."Processing Status" := BusinessEntity."Processing Status"::Processed;
+        BusinessEntity."Processed Date" := Today;
+        BusinessEntity.Modify(true);
+    end;
+}
