diff --git a/src/OutboxEmailDispatcher.Codeunit.al b/src/OutboxEmailDispatcher.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/OutboxEmailDispatcher.Codeunit.al
@@ -0,0 +1,57 @@
+codeunit 57301 "Outbox Email Dispatcher"
+{
+    Access = Public;
+
+    procedure SendPendingEmails()
+    var
+        OutboxEmail: Record "EA Outbox Email";
+        HttpClient: HttpClient;
+        Content: HttpContent;
+        ContentHeaders: HttpHeaders;
+        Response: HttpResponseMessage;
+        PayloadText: Text;
+    begin
+        OutboxEmail.SetRange("Send Status", OutboxEmail."Send Status"::Pending);
+        if OutboxEmail.FindSet(true) then
+            repeat
+                PayloadText := BuildMailPayload(OutboxEmail);
+                Content.WriteFrom(PayloadText);
+                Content.GetHeaders(ContentHeaders);
+                ContentHeaders.Add('Content-Type', 'application/json');
+                if HttpClient.Post(GraphSendMailUrlTok, Content, Response) then begin
+                    if Response.IsSuccessStatusCode() then
+                        OutboxEmail."Send Status" := OutboxEmail."Send Status"::Sent
+                    else
+                        OutboxEmail."Send Status" := OutboxEmail."Send Status"::Failed;
+                    OutboxEmail.Modify(true);
+                end;
+            until OutboxEmail.Next() = 0;
+    end;
+
+    local procedure BuildMailPayload(OutboxEmail: Record "EA Outbox Email"): Text
+    var
+        Message: JsonObject;
+        Body: JsonObject;
+        Recipient: JsonObject;
+        EmailAddress: JsonObject;
+        ToRecipients: JsonArray;
+        Root: JsonObject;
+        PayloadText: Text;
+    begin
+        Body.Add('contentType', 'HTML');
+        Body.Add('content', OutboxEmail.GetBodyText());
+        EmailAddress.Add('address', OutboxEmail."To Line");
+        Recipient.Add('emailAddress', EmailAddress);
+        ToRecipients.Add(Recipient);
+        Message.Add('subject', OutboxEmail.Subject);
+        Message.Add('toRecipients', ToRecipients);
+        Message.Add('body', Body);
+        Root.Add('message', Message);
+        Root.Add('saveToSentItems', true);
+        Root.WriteTo(PayloadText);
+        exit(PayloadText);
+    end;
+
+    var
+        GraphSendMailUrlTok: Label 'https://graph.microsoft.com/v1.0/me/sendMail', Locked = true;
+}

