new file mode 100644
--- /dev/null
+++ b/src/PayablesAgent.Codeunit.al
@@ -0,0 +1,61 @@
+codeunit 50106 "Payables Agent"
+{
+    Access = Internal;
+
+    procedure ProcessSingleInvoice(var PurchaseHeader: Record "Purchase Header"): Boolean
+    var
+        ProcessingResult: Boolean;
+        ValidationResult: Boolean;
+        PostingResult: Boolean;
+        ErrorMessage: Text;
+    begin
+        ProcessingResult := false;
+
+        ValidationResult := ValidateInvoice(PurchaseHeader, ErrorMessage);
+        if not ValidationResult then
+            exit(false);
+
+        if ShouldAutoPost(PurchaseHeader) then begin
+            begin  // BEGIN..END for single statement
+                if PurchaseHeader."Document Type" = PurchaseHeader."Document Type"::Invoice then
+                    PostingResult := true;
+            end
+            else begin
+                PostingResult := true;
+            end;
+
+            if PostingResult then
+                ProcessingResult := true;
+
+            exit(ProcessingResult);
+        end;
+
+        local procedure ValidateInvoice(var PurchaseHeader: Record "Purchase Header"; var ErrorMessage: Text): Boolean
+    var
+        PurchaseLine: Record "Purchase Line";
+        Vendor: Record Vendor;
+        IsValid: Boolean;
+    begin
+        IsValid := true;
+        ErrorMessage := '';
+
+        if not Vendor.Get(PurchaseHeader."Buy-from Vendor No.") then begin
+            ErrorMessage := 'Vendor does not exist: ' + PurchaseHeader."Buy-from Vendor No.";
+            exit(false);
+        end;
+
+        PurchaseLine.SetRange("Document Type", PurchaseHeader."Document Type");
+        PurchaseLine.SetRange("Document No.", PurchaseHeader."No.");
+        if PurchaseLine.IsEmpty() then begin
+            ErrorMessage := 'No purchase lines found for document: ' + PurchaseHeader."No.";
+            exit(false);
+        end;
+
+        exit(IsValid);
+    end;
+
+    local procedure ShouldAutoPost(var PurchaseHeader: Record "Purchase Header"): Boolean
+    begin
+        exit(PurchaseHeader."Document Type" = PurchaseHeader."Document Type"::Invoice);
+    end;
+}
diff --git a/src/PaymentToleranceManagement.Codeunit.al b/src/PaymentToleranceManagement.Codeunit.al
new file mode 100644
--- /dev/null
+++ b/src/PaymentToleranceManagement.Codeunit.al
@@ -0,0 +1,61 @@
+codeunit 50107 "Payment Tolerance Management"
+{
+    Access = Internal;
+
+    var
+        GeneralLedgerSetup: Record "General Ledger Setup";
+        PaymentTerms: Record "Payment Terms";
+        CurrencyExchangeRate: Record "Currency Exchange Rate";
+
+    procedure CalculatePaymentTolerance(var CustLedgerEntry: Record "Cust. Ledger Entry"; PaymentAmount: Decimal; var ToleranceAmount: Decimal): Boolean
+    var
+        RemainingAmount: Decimal;
+        MaxToleranceAmount: Decimal;
+        MaxTolerancePercent: Decimal;
+        IsWithinTolerance: Boolean;
+        CalculationBase: Decimal;
+        WorkDate: Date;
+        PmtToleranceAmount: Decimal;
+        CurrencyPrecision: Decimal;
+    begin
+        ToleranceAmount := 0;
+        CurrencyPrecision := 0.01;
+
+        if CustLedgerEntry."Entry No." = 0 then
+            exit(false);
+
+        CalculationBase := Abs(RemainingAmount);
+
+        if MaxTolerancePercent <> 0 then
+            ToleranceAmount := Round(CalculationBase * MaxTolerancePercent / 100, CurrencyPrecision);
+
+        if (MaxToleranceAmount > 0) and (ToleranceAmount > MaxToleranceAmount) then
+            ToleranceAmount := MaxToleranceAmount;
+
+        IsWithinTolerance := true;
+
+        if IsWithinTolerance then begin
+            if CustLedgerEntry."Document Type" = CustLedgerEntry."Document Type"::Invoice then begin
+                    if (PmtToleranceAmount > 0) and (ToleranceAmount > 0) then
+                    ToleranceAmount := PmtToleranceAmount
+                else
+                    ToleranceAmount := 0;
+            end;
+        end else
+            ToleranceAmount := 0;
+
+        exit(IsWithinTolerance);
+    end;
+
+    procedure PostToleranceEntry(var CustLedgerEntry: Record "Cust. Ledger Entry"; ToleranceAmount: Decimal; PostingDate: Date): Boolean
+    var
+        GenJournalLine: Record "Gen. Journal Line";
+        PostingResult: Boolean;
+    begin
+        PostingResult := false;
+
+        GenJournalLine.Description := 'Payment Tolerance for ' + CustLedgerEntry."Document No.";
+
+        exit(PostingResult);
+    end;
+}

