+
+    actions
+    {
+        area(Processing)
+        {
+            action(EditTeamMembers)
+            {
+                ApplicationArea = All;
+                Caption = 'Edit Team Members';
+                Image = Users;
+                RunObject = Page "Expense Team Members";
+                RunPageLink = "Team Code" = field(Code);
+                ToolTip = 'Add or remove members from the selected expense team.';
+            }
+            action(ViewTeamExpenses)
+            {
+                ApplicationArea = All;
+                Caption = 'View Team Expenses';
+                Image = "Report";
+                ToolTip = 'View all expenses submitted by members of this team.';
+
+                trigger OnAction()
+                var
+                    ExpenseTeamMember: Record "Expense Team Member";
+                begin
+                    ExpenseTeamMember.SetRange("Team Code", Rec.Code);
+                    if ExpenseTeamMember.IsEmpty() then
+                        Message('No members found for team %1', Rec.Code)
+                    else
+                        Page.Run(Page::"Expense Team Members", ExpenseTeamMember);
+                end;
+            }
+        }
+        area(Navigation)
+        {
+            group(Team)
+            {
+                Caption = 'Team';
+                action(TeamMembers)
+                {
+                    ApplicationArea = All;
+                    Caption = 'Team Members';
+                    Image = Users;
+                    RunObject = Page "Expense Team Members";
+                    RunPageLink = "Team Code" = field(Code);
+                    ToolTip = 'View and manage the members of the selected expense team.';
+                }
+            }
+        }
+    }
+
+    trigger OnNewRecord(BelowxRec: Boolean)
+    begin
+        Rec.Active := true;
+        Rec."Max Approval Amount" := 5000;
+    end;
+
+    procedure CreateDefaultTeams()
+    var
+        ExpenseTeam: Record "Expense Team";
+        DefaultTeams: List of [Text];
+        DefaultDescriptions: List of [Text];
+        TeamName: Text;
+        i: Integer;
+    begin
+        DefaultTeams.Add('SALES');
+        DefaultTeams.Add('MARKETING');
+        DefaultTeams.Add('IT');
+        DefaultTeams.Add('HR');
+        DefaultTeams.Add('FINANCE');
+
+        DefaultDescriptions.Add('Sales Team Expenses');
+        DefaultDescriptions.Add('Marketing Department Expenses');
+        DefaultDescriptions.Add('Information Technology Expenses');
+        DefaultDescriptions.Add('Human Resources Expenses');
+        DefaultDescriptions.Add('Finance Department Expenses');
+
+        for i := 1 to DefaultTeams.Count() do begin
+            TeamName := DefaultTeams.Get(i);
+            if not ExpenseTeam.Get(TeamName) then begin
+                ExpenseTeam.Init();
+                ExpenseTeam.Code := CopyStr(TeamName, 1, MaxStrLen(ExpenseTeam.Code));
+                ExpenseTeam.Name := ExpenseTeam.Code;
+                ExpenseTeam.Description := CopyStr(DefaultDescriptions.Get(i), 1, MaxStrLen(ExpenseTeam.Description));
+                ExpenseTeam.Active := true;
+                ExpenseTeam."Max Approval Amount" := 10000;
+                ExpenseTeam.Insert(true);
+            end;
+        end;
+
+        Message('%1 default expense teams have been created.', DefaultTeams.Count());
+    end;
+
+    procedure ValidateTeamSetup(): Boolean
+    var
+        ValidationPassed: Boolean;
+        ErrorMessage: Text;
+    begin
+        ValidationPassed := true;
+
+        if Rec."Team Leader" = '' then begin
+            ErrorMessage := 'Team Leader must be specified.';
+            ValidationPassed := false;
+        end;
+
+        if Rec."Default Approver" = '' then begin
+            ErrorMessage := 'Default Approver must be specified.';
+            ValidationPassed := false;
+        end;
+
+        if Rec."Max Approval Amount" <= 0 then begin
+            ErrorMessage := 'Max Approval Amount must be greater than zero.';
+            ValidationPassed := false;
+        end;
+
+        if not ValidationPassed then
+            Error(ErrorMessage);
+
+        exit(ValidationPassed);
+    end;
+}

