diff --git a/src/CustomerListEnhancements.PageExt.al b/src/CustomerListEnhancements.PageExt.al
new file mode 100644
--- /dev/null
+++ b/src/CustomerListEnhancements.PageExt.al
@@ -0,0 +1,47 @@
+pageextension 50103 CustomerListEnhancements extends "Customer List"
+{
+  actions
+  {
+    addlast(processing)
+    {
+      action(ExportToExcel)
+      {
+        ApplicationArea = All;
+        Caption = 'Export to Excel';
+        Image = Excel;
+        ToolTip = 'Exports the customer list to an Excel workbook using the standard Excel buffer.';
+
+        trigger OnAction()
+        var
+          Customer: Record Customer;
+          TempExcelBuffer: Record "Excel Buffer" temporary;
+        begin
+          TempExcelBuffer.DeleteAll();
+
+          TempExcelBuffer.NewRow();
+          TempExcelBuffer.AddColumn(CustomerNoCaptionLbl, false, '', false, false, false, '', TempExcelBuffer."Cell Type"::Text);
+          TempExcelBuffer.AddColumn(NameCaptionLbl, false, '', false, false, false, '', TempExcelBuffer."Cell Type"::Text);
+
+          Customer.Copy(Rec);
+          Customer.SetLoadFields("No.", Name);
+          if Customer.FindSet() then
+            repeat
+              TempExcelBuffer.NewRow();
+              TempExcelBuffer.AddColumn(Customer."No.", false, '', false, false, false, '', TempExcelBuffer."Cell Type"::Text);
+              TempExcelBuffer.AddColumn(Customer.Name, false, '', false, false, false, '', TempExcelBuffer."Cell Type"::Text);
+            until Customer.Next() = 0;
+
+          TempExcelBuffer.CreateNewBook(SheetNameLbl);
+          TempExcelBuffer.WriteSheet(SheetNameLbl, CompanyName(), UserId());
+          TempExcelBuffer.CloseBook();
+          TempExcelBuffer.OpenExcel();
+        end;
+      }
+    }
+  }
+
+  var
+    CustomerNoCaptionLbl: Label 'Customer No.';
+    NameCaptionLbl: Label 'Name';
+    SheetNameLbl: Label 'Customers';
+}
