@@ -0,0 +1,65 @@
+table 50105 "Migration Status Tracker"
+{
+  Caption = 'Migration Status Tracker';
+  DataClassification = SystemMetadata;
+  TableType = Temporary;
+
+  fields
+  {
+    field(1; "Migration ID"; Guid)
+    {
+      DataClassification = SystemMetadata;
+      Caption = 'Migration ID';
+    }
+    field(2; "Table Name"; Text[100])
+    {
+      DataClassification = SystemMetadata;
+      Caption = 'Table Name';
+    }
+    field(3; "Records Processed"; Integer)
+    {
+      DataClassification = SystemMetadata;
+      Caption = 'Records Processed';
+    }
+    field(4; "Status"; Option)
+    {
+      DataClassification = SystemMetadata;
+      OptionMembers = Pending,InProgress,Completed,Failed;
+      OptionCaption = 'Pending,In Progress,Completed,Failed';
+      Caption = 'Status';
+    }
+  }
+
+  keys
+  {
+    key(PK; "Migration ID", "Table Name")
+    {
+      Clustered = true;
+    }
+  }
+
+  procedure InitializeMigration(TableName: Text[100]): Guid
+  var
+    MigrationId: Guid;
+  begin
+    MigrationId := CreateGuid();
+
+    Rec.Init();
+    Rec."Migration ID" := MigrationId;
+    Rec."Table Name" := TableName;
+    Rec.Status := Rec.Status::Pending;
+    Rec."Records Processed" := 0;
+    Rec.Insert(false);
+
+    exit(MigrationId);
+  end;
+
+  procedure UpdateProgress(MigrationId: Guid; TableName: Text[100]; RecordsProcessed: Integer)
+  begin
+    if Rec.Get(MigrationId, TableName) then begin
+      Rec."Records Processed" := RecordsProcessed;
+      Rec.Status := Rec.Status::InProgress;
+      Rec.Modify(false);
+    end;
+  end;
+}
